CREATE TABLE api_key_model_scopes (api_key_id VARCHAR(36) NOT NULL, model_id VARCHAR(36) NOT NULL, PRIMARY KEY (api_key_id,model_id), KEY idx_api_key_model_scopes_model (model_id,api_key_id), CONSTRAINT fk_api_key_model_scopes_key FOREIGN KEY (api_key_id) REFERENCES api_keys (id), CONSTRAINT fk_api_key_model_scopes_model FOREIGN KEY (model_id) REFERENCES content_models (id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_as_cs;
